from typing import List


def separate_paren_groups(paren_string: str) -> List[str]:
    result = []
    current_group = ''
    paren_stack = []

    for char in paren_string:
        if char == '(':
            paren_stack.append(char)
            if len(paren_stack) == 1:
                current_group += char
        elif char == ')':
            paren_stack.pop()
            if len(paren_stack) == 0:
                result.append(current_group)
                current_group = ''
    return result

